load("lab4_exp1_data.mat")

% EKV Parameters Plot
[Is_Q1, VT_Q1, kappa_Q1] = ekvfit(Vg_Q1, I_circuit_Q1, 1e-4);
[Is_Q2, VT_Q2, kappa_Q2] = ekvfit(Vg_Q2, I_circuit_Q2, 1e-4);
[Is_Q3, VT_Q3, kappa_Q3] = ekvfit(Vg_Q3, I_circuit_Q3, 1e-4);
[Is_Q4, VT_Q4, kappa_Q4] = ekvfit(Vg_Q4, I_circuit_Q4, 1e-4);

numerical_ekv_prediction_Q1 = Is_Q1 .* (log(1 + exp(kappa_Q1 .* (Vg_Q1 - VT_Q1) ./ (2 .* 0.0258)))).^2;

figure(); %[output:0d12dd69]
semilogy(Vg_Q1, I_circuit_Q1, '.', DisplayName='Measured Data - MOSFET 1') %[output:0d12dd69]
hold on; %[output:0d12dd69]
semilogy(Vg_Q2, I_circuit_Q2, '.', DisplayName='Measured Data - MOSFET 2') %[output:0d12dd69]
semilogy(Vg_Q3, I_circuit_Q3, '.', DisplayName='Measured Data - MOSFET 3') %[output:0d12dd69]
semilogy(Vg_Q4, I_circuit_Q4, '.', DisplayName='Measured Data - MOSFET 4') %[output:0d12dd69]

semilogy(Vg_Q1, numerical_ekv_prediction_Q1, DisplayName='EKV Model Prediction - MOSFET 1') %[output:0d12dd69]

xlabel('Gate Voltage (V)') %[output:0d12dd69]
ylabel('Drain-Source Current (A)') %[output:0d12dd69]
title('Current-Voltage Characteristics of MOSFETs') %[output:0d12dd69]
legend(Location='southoutside') %[output:0d12dd69]

% Variation between Transistors
I_circuit_All = [I_circuit_Q1; I_circuit_Q2; I_circuit_Q3; I_circuit_Q4];
I_circuit_Avg = mean(I_circuit_All, 1);

figure(); %[output:6ecba8e8]
semilogy(Vg_Q1, abs(I_circuit_Q1 - I_circuit_Avg), '.', DisplayName='MOSFET 1') %[output:6ecba8e8]
hold on %[output:6ecba8e8]
semilogy(Vg_Q2, abs(I_circuit_Q2 - I_circuit_Avg), '.', DisplayName='MOSFET 2') %[output:6ecba8e8]
semilogy(Vg_Q3, abs(I_circuit_Q3 - I_circuit_Avg), '.', DisplayName='MOSFET 3') %[output:6ecba8e8]
semilogy(Vg_Q4, abs(I_circuit_Q4 - I_circuit_Avg), '.', DisplayName='MOSFET 4') %[output:6ecba8e8]

xlabel('Gate Voltage (V)') %[output:6ecba8e8]
ylabel('Magnitude of Variation in Drain-Source Current (A)') %[output:6ecba8e8]
title('Variation in Current-Voltage Characteristics of MOSFETs') %[output:6ecba8e8]
legend(Location='southoutside') %[output:6ecba8e8]

% Transconductance Gain
transconductance_gain_Q1 = (diff(I_circuit_Q1)) ./ (diff(Vg_Q1));
S = 0.8;
transconductance_gain_prediction_Q1 = (kappa_Q1 / 0.025) .* sqrt(S .* Is_Q1 .* I_circuit_Q1) .* (1 - exp(-sqrt(I_circuit_Q1 ./ (S * Is_Q1))));

figure() %[output:4706f07a]
loglog(I_circuit_Q1(1:end-1), transconductance_gain_Q1, '.', DisplayName='MOSFET 1') %[output:4706f07a]
hold on %[output:4706f07a]
loglog(I_circuit_Q1, transconductance_gain_prediction_Q1, DisplayName='EKV Model Prediction - MOSFET 1') %[output:60704cb0] %[output:4706f07a]

xlabel('Drain-Source Current (A)') %[output:4706f07a]
ylabel(['Transconductance Gain (', char(8487), ')']) %[output:4706f07a]
title('Transconductance Gain of MOSFET') %[output:4706f07a]
legend(Location='southoutside') %[output:4706f07a] %[output:2ea13747] %[output:54c24518] %[output:91155ac6]

